using System;
using System.Data.SqlClient;

public class LoginValidator
{
    public static bool ValidateCredentials(string username, string password)
    {
        // SQL query to check if credentials match
        string sqlQuery = "SELECT COUNT(*) FROM users WHERE username = @username AND password = @password";

        using (SqlConnection connection = new SqlConnection("Server=(local);Database=mydatabase;Integrated Security=True"))
        {
            SqlCommand command = new SqlCommand(sqlQuery, connection);
            command.Parameters.AddWithValue("@username", username);
            command.Parameters.AddWithValue("@password", password);

            try
            {
                connection.Open();
                int result = (int)command.ExecuteScalar();
                return result > 0;
            }
            catch (SqlException e)
